        reader = csv.DictReader(f)
        for row in reader:
            results.append({
                "prompt_id": int(row["prompt_id"]),
                "toxicity_score": float(row["toxicity_score"]),
                "is_toxic": row["is_toxic"] == "True"
            })

    return results

